UPDATE public.courses SET detail_content = '{"longDescription":"FunTech Explorers è un corso online divertente e interattivo, pensato per introdurre i bambini alle principali componenti del computer, alle basi della programmazione a blocchi e all''uso del computer. Gli studenti svilupperanno il pensiero logico e critico attraverso giochi, strumenti interattivi e progetti creativi. Il corso affronterà diversi argomenti presentati in modo non lineare, per mantenere alto l''interesse degli studenti. Sono inclusi anche esercizi supplementari di matematica, utili per sviluppare abilità di calcolo e pensiero algoritmico.","age":"5-7 anni","level":"Principiante","duration":"32 lezioni","tags":["Programmazione","Matematica","Creazione","Informatica di base","Uso del computer"],"topics":["Sviluppare il pensiero creativo e la creatività","Insegnare le basi dell''alfabetizzazione digitale","Sviluppare competenze di base nella programmazione a blocchi","Padroneggiare strumenti di creatività digitale per la realizzazione di progetti"],"projectExamples":[{"title":"Progetto creativo con Scratch Junior"},{"title":"Gioco interattivo"},{"title":"Animazione musicale"}],"modules":[{"title":"Modulo 1. Scoprire il Mondo Digitale","lessons":["1. Conoscere il mouse e la tastiera","2. All''avventura! Imparare gli algoritmi","3. Viaggiare con un robot! Giocare con giochi di digitazione e imparare le sequenze","4. La città del futuro: affrontare sfide logiche nel nostro viaggio"],"result":"Grazie a questo modulo, i bambini impareranno a conoscere il computer: impareranno a usare il mouse e a digitare sulla tastiera. Inoltre, creeranno i loro primi algoritmi e risolveranno molti problemi logici."},{"title":"Modulo 2. Un entusiasmante Viaggio nel Coding","lessons":["5. Nozioni di base sulla programmazione: sequenzialità e abilità di digitazione","6. Ripetizioni divertenti e puzzle: una lezione sui cicli e sulla logica","7. Puzzle logici e piattaforma degli avventurieri","8. Il Laboratorio di Giochi. Migliora le tue abilità di digitazione!"],"result":"Grazie a questo modulo, i bambini continueranno i loro studi di programmazione e problemi logici. Impareranno il concetto di loop e come risolvere sequenze complesse."},{"title":"Modulo 3. Avventure nella Valle dei Dati: la Magia del Computer","lessons":["9. Little Bit e la valle dei dati","10. La grande avventura delle cartelle","11. Viaggiando attraverso il World Wide Web","12. Il detective dei dati"],"result":"Grazie a questo modulo, i bambini acquisiranno familiarità con la struttura dei file di un computer, impareranno cos''è Internet e come esplorarlo con i browser web."},{"title":"Modulo 4. Techno-creators: costruire, cercare, creare!","lessons":["13. Una festa da ballo con Scratch Junior","14. Costruire una fattoria!","15. Andare nello spazio con un razzo!","16. Le quattro stagioni"],"result":"I bambini creano un cartone animato in Scratch Junior imparando la piattaforma. Rafforzeranno le loro abilità di programmazione a blocchi attraverso la creazione di progetti."},{"title":"Modulo 5. Cyber Sorcery: Un''avventura nel Mondo della Tecnologia!","lessons":["17. Il mondo sommerso della programmazione","18. Il potere dei messaggi in Scratch Junior","19. Cartoline dal vivo in Scratch Junior","20. Personaggi dei cartoni animati sullo schermo!"],"result":"Durante questo modulo, i bambini continueranno lo studio di Scratch Junior. Creeranno il loro gioco e impareranno nuovi blocchi per la programmazione dei giochi."},{"title":"Modulo 6. Avventura nel Mondo dei Numeri e della Tecnologia","lessons":["21. I maghi della Matematica: Imparare sui numeri","22. Eroi dei Numeri: il Viaggio della Matematica","23. Google Fogli: Un magico mondo di numeri","24. Google Fogli: il festival dei Numeri"],"result":"Grazie a questo modulo, i bambini impareranno le operazioni matematiche di base e le applicheranno man mano che vengono introdotti a Google Fogli."},{"title":"Modulo 7. Cyber Creators: Storie, musica e magia","lessons":["25. Il mio primo gioco: catturare Zippy","26. Le Avventure nel mondo dei Videogiochi","27. Le Meraviglie dei Videogiochi","28. Lancio Stellare: il mio Gioco è pronto!"],"result":"Grazie a questo modulo, gli studenti continueranno ad apprendere la programmazione a blocchi in Scratch e creeranno nuovi giochi completi!"},{"title":"Modulo 8. La Sfida Finale","lessons":["29. Cyber-Revision: Tutto sulle Competenze Digitali","30. Maratona di Programmazione: un Viaggio attraverso il Codice","31. Missione Creativa Finale","32. Il fantastico Diploma: celebrare il successo"],"result":"Grazie a questo modulo, i bambini potranno ripassare in modo divertente tutto il materiale appreso e creare il proprio portfolio digitale che riflette il percorso compiuto!"}]}'::jsonb WHERE slug = 'abc-informatica' AND (detail_content IS NULL OR detail_content = '{}'::jsonb);

UPDATE public.courses SET detail_content = '{"longDescription":"Questo corso è per bambini della scuola primaria che vogliono approcciarsi alla sfera dell''Information Technology. Con l''aiuto della programmazione visiva in Scratch, gli studenti saranno in grado di sviluppare non solo il loro pensiero logico ma anche le loro abilità creative. Durante il corso, i bambini trasformeranno vari progetti e impareranno come creare giochi e cartoni in modo indipendente.","age":"8-10 anni","level":"Principiante","duration":"32 lezioni","tags":["Scratch","Creatività","Sviluppo di giochi","Animazione"],"topics":["Crea i tuoi giochi in 2D","Crea i tuoi personaggi","Crea i tuoi progetti su Scratch","Conoscenza dei concetti di base di algoritmi e programmazione","Abilità di applicare variabili, loop e condizioni","Abilità di creare la fisica dei giochi: scrolling, gravità, cambio di velocità"],"projectExamples":[{"title":"Gioco 2D completo"},{"title":"Animazione interattiva"},{"title":"Storia animata"}],"modules":[{"title":"М1: I primi progetti con Scratch","lessons":["1. Basi di Scratch. Il primo progetto.","2. Movimento degli Sprite su Scratch.","3. Editor grafico magico. Crea il tuo assistente magico personale!","4. Il Debugging dei progetti. Cos''è un bug?","5. Koddich - una competizione di programmazione per i veri maghi!"],"result":"Il primissimo progetto Scratch alla Scuola di Magia Kodewarts."},{"title":"М2: Animazioni e Suoni in Kodewarts","lessons":["6. Scratch-eventi.","7. Principi di animazione.","8. Sfondi e musica.","9. Crea il tuo gruppo musicale personale!"],"result":"Un''eccezionale app musicale animata."},{"title":"М3: La magia di creare i giochi","lessons":["10. Cos''è un gioco?","11. Giochi per Principianti.","12. Segnare il punteggio: imparare a lavorare con le variabili.","13. Interazione nei giochi.","14. Livelli Bonus. Imparare a rendere i giochi più difficili.","15. Creare un gioco puzzle con Scratch!","16. La seconda stagione di Koddich!"],"result":"Un gioco completo contenente meccaniche di gameplay base."},{"title":"М4: Il ruolo della narrazione nel processo di sviluppo del gioco","lessons":["17. Meccaniche di gameplay - gli ingredienti per un gran gioco!","18. Dialoghi e testi nei giochi.","19. Blocchi personalizzati: perché ci servono e come crearli.","20. Lo sviluppo dello scenario del gioco.","21. Imparare come creare personaggi e scene dirette.","22. Cercando bug!","23. Koddich: Finale."],"result":"Giochi basati su una storia con Scratch."},{"title":"М5: Scratch avanzato","lessons":["24. Estensioni di Scratch.","25. Imparare come riconoscere i video!","26. Creare cloni.","27. Sviluppo del design del programma.","28. Un''altra sessione di debug!"],"result":"Progetti Scratch con fantastiche possibilità."},{"title":"М6: Hackathon. Creare un progetto per il diploma!","lessons":["29. Come la pianificazione attenta può aiutarti a creare i migliori progetti!","30. Sviluppare il nostro miglior progetto in assoluto!","31. Perché i test e i feedback sono così importanti?","32. I segreti dietro una dimostrazione di successo!"],"result":"Un progetto unico che ha passato tutte le fasi di sviluppo."}]}'::jsonb WHERE slug = 'scratch' AND (detail_content IS NULL OR detail_content = '{}'::jsonb);
